import React, { useState } from 'react';
import { View, TextInput, Button, Text } from 'react-native';

const App = () => {
  const [code, setCode] = useState('');
  const [token, setToken] = useState('');

  const handleAuthorization = async () => {
    try {
      const response = await fetch('https://your-auth-server.com/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: `grant_type=authorization_code&code=${code}&client_id=mobile_app_client_123&client_secret=secret_abc123xyz456`
      });

      const data = await response.json();
      setToken(data.access_token);
    } catch (error) {
      console.error('Error exchanging authorization code for token:', error);
    }
  };

  return (
    <View style={{ padding: 20 }}>
      <Text>Authorization Code:</Text>
      <TextInput
        style={{ height: 40, borderColor: 'gray', borderWidth: 1 }}
        onChangeText={setCode}
        value={code}
      />
      <Button title="Exchange for Token" onPress={handleAuthorization} />
      {token && <Text>Access Token: {token}</Text>}
    </View>
  );
};

export default App;